import Foundation

struct PromoLink {
    let code: String?
    let discount: Double?
}

func extractPromoLink(from urlString: String) -> PromoLink? {
    guard let url = URL(string: urlString) else { return nil }

    var components = URLComponents(url: url, resolvingAgainstBaseURL: false)
    if let queryItems = components?.queryItems {
        for item in queryItems {
            switch item.name {
            case "code":
                return PromoLink(code: item.value, discount: nil)
            case "discount":
                guard let discount = Double(item.value), discount >= 0 && discount <= 100 else { continue }
                if let code = components?.queryItems?.first(where: { $0.name == "code" })?.value {
                    return PromoLink(code: code, discount: discount)
                }
            default:
                continue
            }
        }
    }

    return nil
}

struct User {
    var discountPercentage: Double
    // ... other properties and methods
}

func applyPromoCode(to user: inout User, promoLink: PromoLink?) {
    if let promoLink = promoLink {
        user.discountPercentage = promoLink.discount ?? 0
    }
}